mapper.select:
SELECT * FROM pms_product WHERE delete_status = 0
AND (name LIKE concat('%', #{keyword}, '%') OR keywords LIKE concat('%', #{keyword}, '%'))
AND brand_id = #{brandId}
AND product_category_id = #{productCategoryId}
ORDER BY id DESC ORDER BY sale DESC ORDER BY price ASC ORDER BY price DESC ORDER BY sort DESC
